import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { Card, CardContent, TextField, Button, Typography } from "@mui/material";
import axios from "axios";

const EditMedicineType = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [medicineType, setMedicineType] = useState({
        code: "",
        name: ""
    });

    useEffect(() => {
        axios.get(`/api/medicine-types/${id}`)
            .then((response) => {
                setMedicineType(response.data);
            })
            .catch((error) => {
                console.error("Error fetching medicine type:", error);
            });
    }, [id]);

    const handleChange = (e) => {
        setMedicineType({ ...medicineType, [e.target.name]: e.target.value });
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        axios.put(`/api/medicine-types/${id}`, medicineType)
            .then(() => {
                navigate("/medicine-types");
            })
            .catch((error) => {
                console.error("Error updating medicine type:", error);
            });
    };

    return (
        <Card sx={{ maxWidth: 600, margin: "auto", mt: 5, p: 3 }}>
            <CardContent>
                <Typography variant="h5" gutterBottom>
                    Chỉnh sửa loại thuốc
                </Typography>
                <form onSubmit={handleSubmit}>
                    <TextField
                        fullWidth
                        label="Mã loại thuốc"
                        name="code"
                        value={medicineType.code}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Tên loại thuốc"
                        name="name"
                        value={medicineType.name}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <Button type="submit" variant="contained" color="primary" sx={{ mt: 2, mr: 2 }}>
                        Lưu lại
                    </Button>
                    <Button variant="outlined" color="secondary" sx={{ mt: 2 }} onClick={() => navigate("/medicine-types")}>
                        Quay lại
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
};

export default EditMedicineType;
